24.             _store.Save(p with { Price = p.Price * (1 - fraction) });
25.     }
26.     public string ExportToCsv() =>
27.         string.Join("\n", _store.GetAll().Select(p => $"{p.Sku},{p.Name},{p.Price}"));
28.     public void ImportFromCsv(string csv)
29.     {
30.         foreach (var line in csv.Split('\n'))
31.         {
32.             var parts = line.Split(',');
